# pip install openai
from __future__ import annotations
import json
import os
import time
from pathlib import Path
from typing import Optional
from openai import OpenAI
from openai.types.beta import Thread
from openai.types.beta.threads import Run

client = OpenAI(api_key=os.environ['OPENAI_API_KEY'])


# ── 1. Create a persistent assistant ──────────────────────────────────────────

def create_assistant(
    name: str,
    instructions: str,
    tools: Optional[list[dict]] = None,
    model: str = 'gpt-4o-mini',
) -> str:  # returns assistant_id
    assistant = client.beta.assistants.create(
        name=name,
        instructions=instructions,
        tools=tools or [],
        model=model,
    )
    print(f'Created assistant: {assistant.id} ({assistant.name})')
    return assistant.id


def get_or_create_assistant(name: str, instructions: str, tools: list[dict], model: str = 'gpt-4o-mini') -> str:
    """Retrieve existing assistant by name or create a new one."""
    existing = client.beta.assistants.list(limit=20)
    for a in existing.data:
        if a.name == name:
            print(f'Using existing assistant: {a.id}')
            return a.id
    return create_assistant(name, instructions, tools, model)


# ── 2. Thread management ──────────────────────────────────────────────────────

def create_thread() -> str:
    thread = client.beta.threads.create()
    return thread.id


def add_message(thread_id: str, content: str, role: str = 'user') -> None:
    client.beta.threads.messages.create(
        thread_id=thread_id,
        role=role,
        content=content,
    )


def get_messages(thread_id: str, limit: int = 10) -> list[dict]:
    messages = client.beta.threads.messages.list(thread_id=thread_id, limit=limit, order='asc')
    result = []
    for msg in messages.data:
        text_content = next(
            (c.text.value for c in msg.content if hasattr(c, 'text')), ''
        )
        result.append({'role': msg.role, 'content': text_content})
    return result


# ── 3. Run with polling ────────────────────────────────────────────────────────

TOOL_REGISTRY: dict[str, callable] = {}

def register_tool(name: str, fn: callable) -> None:
    TOOL_REGISTRY[name] = fn


def run_and_wait(
    thread_id: str,
    assistant_id: str,
    max_wait_seconds: int = 60,
) -> str:  # returns last assistant message
    run = client.beta.threads.runs.create(
        thread_id=thread_id,
        assistant_id=assistant_id,
    )

    start = time.time()
    while time.time() - start < max_wait_seconds:
        run = client.beta.threads.runs.retrieve(thread_id=thread_id, run_id=run.id)

        if run.status == 'completed':
            messages = get_messages(thread_id, limit=1)
            return messages[-1]['content'] if messages else ''

        elif run.status == 'requires_action':
            tool_calls = run.required_action.submit_tool_outputs.tool_calls
            outputs = []
            for tc in tool_calls:
                fn = TOOL_REGISTRY.get(tc.function.name)
                if fn:
                    args = json.loads(tc.function.arguments)
                    result = fn(**args)
                else:
                    result = json.dumps({'error': f'Unknown tool: {tc.function.name}'})
                outputs.append({'tool_call_id': tc.id, 'output': str(result)})

            run = client.beta.threads.runs.submit_tool_outputs(
                thread_id=thread_id, run_id=run.id, tool_outputs=outputs
            )

        elif run.status in ('failed', 'cancelled', 'expired'):
            error = getattr(run, 'last_error', None)
            return f'Run failed: {run.status} — {error}'

        time.sleep(1)

    return 'Timeout: run did not complete in time'


# ── 4. Run with streaming ─────────────────────────────────────────────────────

def run_streaming(thread_id: str, assistant_id: str) -> str:
    full_text = ''
    with client.beta.threads.runs.stream(
        thread_id=thread_id,
        assistant_id=assistant_id,
    ) as stream:
        for event in stream:
            # Text delta events
            if hasattr(event, 'data') and hasattr(event.data, 'delta'):
                delta = event.data.delta
                if hasattr(delta, 'content'):
                    for block in delta.content or []:
                        if hasattr(block, 'text') and block.text:
                            chunk = block.text.value or ''
                            print(chunk, end='', flush=True)
                            full_text += chunk
    print()  # newline after stream
    return full_text


# ── 5. File Search assistant ──────────────────────────────────────────────────

def setup_file_search_assistant(
    name: str,
    file_paths: list[str],
) -> tuple[str, str]:  # (assistant_id, vector_store_id)
    """Create assistant with File Search over uploaded documents."""
    # Upload files
    file_ids = []
    for path in file_paths:
        with open(path, 'rb') as f:
            uploaded = client.files.create(file=f, purpose='assistants')
        file_ids.append(uploaded.id)
        print(f'Uploaded {path} → {uploaded.id}')

    # Create vector store
    vs = client.beta.vector_stores.create(
        name=f'{name}_docs',
        file_ids=file_ids,
    )
    # Wait for indexing
    while vs.status != 'completed':
        time.sleep(1)
        vs = client.beta.vector_stores.retrieve(vs.id)
    print(f'Vector store ready: {vs.id} ({vs.file_counts.completed} files indexed)')

    # Create assistant with file_search
    assistant_id = create_assistant(
        name=name,
        instructions='You are a helpful assistant. Answer questions using the provided documents. Cite sources.',
        tools=[{'type': 'file_search'}],
        model='gpt-4o-mini',
    )

    # Attach vector store to assistant
    client.beta.assistants.update(
        assistant_id,
        tool_resources={'file_search': {'vector_store_ids': [vs.id]}},
    )
    print(f'File Search assistant ready: {assistant_id}')
    return assistant_id, vs.id


# ── 6. Session manager (wraps thread lifecycle) ───────────────────────────────

class AssistantSession:
    def __init__(self, assistant_id: str):
        self.assistant_id = assistant_id
        self.thread_id = create_thread()
        print(f'Session started: thread={self.thread_id}')

    def chat(self, message: str, stream: bool = False) -> str:
        add_message(self.thread_id, message)
        if stream:
            return run_streaming(self.thread_id, self.assistant_id)
        return run_and_wait(self.thread_id, self.assistant_id)

    def history(self) -> list[dict]:
        return get_messages(self.thread_id)


# ── Demo ──────────────────────────────────────────────────────────────────────

if __name__ == '__main__':
    # Register a custom tool
    def get_weather(city: str) -> str:
        return json.dumps({'city': city, 'temp': '18°C', 'condition': 'Sunny'})

    register_tool('get_weather', get_weather)

    weather_tool_def = [{
        'type': 'function',
        'function': {
            'name': 'get_weather',
            'description': 'Get current weather for a city',
            'parameters': {
                'type': 'object',
                'properties': {'city': {'type': 'string'}},
                'required': ['city'],
            },
        },
    }]

    # Create a general assistant
    assistant_id = get_or_create_assistant(
        name='Demo Assistant',
        instructions='You are a helpful assistant. Use the weather tool when asked about weather.',
        tools=weather_tool_def,
    )

    # Start a session and chat
    session = AssistantSession(assistant_id)

    questions = [
        "What's the weather in Tokyo?",
        'How does that compare to typical Japanese summers?',  # tests multi-turn memory
    ]

    for q in questions:
        print(f'\nUser: {q}')
        answer = session.chat(q)
        print(f'Assistant: {answer}')

    print('\nFull conversation history:')
    for msg in session.history():
        print(f'  [{msg["role"]}]: {msg["content"][:80]}')
